class Solution:
    def addBinary(self, a: str, b: str) -> str:
        result = []
        carry = 0
        i, j = len(a) - 1, len(b) - 1
        while i >= 0 or j >= 0 or carry:
            s = carry
            if i >= 0:
                s += int(a[i])
                i -= 1
            if j >= 0:
                s += int(b[j])
                j -= 1
            result.append(str(s % 2))
            carry = s // 2
        return ''.join(reversed(result))

solution_js:
var addBinary = function(a, b) {
    let result = [];
    let carry = 0;
    let i = a.length - 1, j = b.length - 1;
    while (i >= 0 || j >= 0 || carry) {
        let s = carry;
        if (i >= 0) s += parseInt(a[i--]);
        if (j >= 0) s += parseInt(b[j--]);
        result.push(s % 2);
        carry = Math.floor(s / 2);
    }
    return result.reverse().join('');
};

