class Solution:
    def widthOfBinaryTree(self, root: Optional[TreeNode]) -> int:
        if not root:
            return 0
        max_width = 0
        queue = [(root, 0)]
        while queue:
            level_length = len(queue)
            _, first_idx = queue[0]
            for i in range(level_length):
                node, idx = queue[i]
                idx -= first_idx  # normalize
                if i == level_length - 1:
                    max_width = max(max_width, idx + 1)
            next_queue = []
            for node, idx in queue:
                idx -= first_idx
                if node.left:
                    next_queue.append((node.left, 2 * idx))
                if node.right:
                    next_queue.append((node.right, 2 * idx + 1))
            queue = next_queue
        return max_width

solution_js:
var widthOfBinaryTree = function(root) {
    if (!root) return 0;
    let maxWidth = 0;
    let queue = [[root, 0n]];
    while (queue.length) {
        const first = queue[0][1];
        const last = queue[queue.length - 1][1];
        maxWidth = Math.max(maxWidth, Number(last - first + 1n));
        const next = [];
        for (const [node, idx] of queue) {
            const i = idx - first;
            if (node.left) next.push([node.left, 2n * i]);
            if (node.right) next.push([node.right, 2n * i + 1n]);
        }
        queue = next;
    }
    return maxWidth;
};

