class Solution:
    def reverse(self, x: int) -> int:
        sign = 1 if x >= 0 else -1
        x = abs(x)
        result = 0
        while x:
            result = result * 10 + x % 10
            x //= 10
        result *= sign
        return result if -2**31 <= result <= 2**31 - 1 else 0

solution_js:
var reverse = function(x) {
    let result = 0;
    while (x !== 0) {
        const digit = x % 10 | 0;
        x = (x / 10) | 0;
        result = result * 10 + digit;
    }
    return result > 2**31 - 1 || result < -(2**31) ? 0 : result;
};

