class Solution:
    def convert(self, s: str, numRows: int) -> str:
        if numRows == 1 or numRows >= len(s):
            return s
        rows = [''] * numRows
        row, step = 0, 1
        for c in s:
            rows[row] += c
            if row == 0:
                step = 1
            elif row == numRows - 1:
                step = -1
            row += step
        return ''.join(rows)

solution_js:
var convert = function(s, numRows) {
    if (numRows === 1 || numRows >= s.length) return s;
    const rows = Array.from({length: numRows}, () => '');
    let row = 0, step = 1;
    for (const c of s) {
        rows[row] += c;
        if (row === 0) step = 1;
        else if (row === numRows - 1) step = -1;
        row += step;
    }
    return rows.join('');
};

