class Solution:
    def compress(self, chars: List[str]) -> int:
        write = 0
        read = 0
        while read < len(chars):
            char = chars[read]
            count = 0
            while read < len(chars) and chars[read] == char:
                read += 1
                count += 1
            chars[write] = char
            write += 1
            if count > 1:
                for d in str(count):
                    chars[write] = d
                    write += 1
        return write

solution_js:
var compress = function(chars) {
    let write = 0, read = 0;
    while (read < chars.length) {
        const char = chars[read];
        let count = 0;
        while (read < chars.length && chars[read] === char) {
            read++;
            count++;
        }
        chars[write++] = char;
        if (count > 1) {
            for (const d of count.toString()) {
                chars[write++] = d;
            }
        }
    }
    return write;
};

