class Solution:
    def findCircleNum(self, isConnected: List[List[int]]) -> int:
        n = len(isConnected)
        visited = set()
        provinces = 0
        def dfs(city):
            visited.add(city)
            for neighbor in range(n):
                if isConnected[city][neighbor] == 1 and neighbor not in visited:
                    dfs(neighbor)
        for i in range(n):
            if i not in visited:
                dfs(i)
                provinces += 1
        return provinces

solution_js:
var findCircleNum = function(isConnected) {
    const n = isConnected.length;
    const visited = new Set();
    let provinces = 0;
    const dfs = (city) => {
        visited.add(city);
        for (let j = 0; j < n; j++) {
            if (isConnected[city][j] === 1 && !visited.has(j)) dfs(j);
        }
    };
    for (let i = 0; i < n; i++) {
        if (!visited.has(i)) {
            dfs(i);
            provinces++;
        }
    }
    return provinces;
};

