        head = root
        while head:
            dummy = Node(0)
            tail = dummy
            curr = head
            while curr:
                if curr.left:
                    tail.next = curr.left
                    tail = tail.next
                if curr.right:
                    tail.next = curr.right
                    tail = tail.next
                curr = curr.next
            head = dummy.next
        return root

