        let d = 1, load = 0;
        for (const w of weights) {
            if (load + w > cap) { d++; load = 0; }
            load += w;
        }
        return d <= days;
    };
    let lo = Math.max(...weights), hi = weights.reduce((a, b) => a + b);
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        canShip(mid) ? hi = mid : lo = mid + 1;
    }
    return lo;
};

