class Solution:
    def searchRange(self, nums: List[int], target: int) -> List[int]:
        def bisect_left(t):
            lo, hi = 0, len(nums)
            while lo < hi:
                mid = (lo + hi) // 2
                if nums[mid] < t:
                    lo = mid + 1
                else:
                    hi = mid
            return lo
        left = bisect_left(target)
        right = bisect_left(target + 1) - 1
        if left <= right and left < len(nums) and nums[left] == target:
            return [left, right]
        return [-1, -1]

