        let lo = 0, hi = nums.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            nums[mid] < t ? lo = mid + 1 : hi = mid;
        }
        return lo;
    };
    const left = bisectLeft(target);
    const right = bisectLeft(target + 1) - 1;
    if (left <= right && left < nums.length && nums[left] === target)
        return [left, right];
    return [-1, -1];
};

