class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class MyLinkedList:
    def __init__(self):
        self.sentinel = ListNode()
        self.size = 0

    def get(self, index: int) -> int:
        if index < 0 or index >= self.size:
            return -1
        curr = self.sentinel.next
        for _ in range(index):
            curr = curr.next
        return curr.val

    def addAtHead(self, val: int) -> None:
        self.addAtIndex(0, val)

    def addAtTail(self, val: int) -> None:
        self.addAtIndex(self.size, val)

    def addAtIndex(self, index: int, val: int) -> None:
        if index > self.size:
            return
        index = max(0, index)
        prev = self.sentinel
        for _ in range(index):
            prev = prev.next
        prev.next = ListNode(val, prev.next)
        self.size += 1

    def deleteAtIndex(self, index: int) -> None:
        if index < 0 or index >= self.size:
            return
        prev = self.sentinel
        for _ in range(index):
            prev = prev.next
        prev.next = prev.next.next
        self.size -= 1

solution_js:
var MyLinkedList = function() {
    this.sentinel = {val: 0, next: null};
    this.size = 0;
};
MyLinkedList.prototype.get = function(index) {
    if (index < 0 || index >= this.size) return -1;
    let curr = this.sentinel.next;
    for (let i = 0; i < index; i++) curr = curr.next;
    return curr.val;
};
MyLinkedList.prototype.addAtHead = function(val) { this.addAtIndex(0, val); };
MyLinkedList.prototype.addAtTail = function(val) { this.addAtIndex(this.size, val); };
MyLinkedList.prototype.addAtIndex = function(index, val) {
    if (index > this.size) return;
    index = Math.max(0, index);
    let prev = this.sentinel;
    for (let i = 0; i < index; i++) prev = prev.next;
    prev.next = {val, next: prev.next};
    this.size++;
};
MyLinkedList.prototype.deleteAtIndex = function(index) {
    if (index < 0 || index >= this.size) return;
    let prev = this.sentinel;
    for (let i = 0; i < index; i++) prev = prev.next;
    prev.next = prev.next.next;
    this.size--;
};

