class Solution:
    def getHint(self, secret: str, guess: str) -> str:
        bulls = 0
        s_count = [0] * 10
        g_count = [0] * 10
        for s, g in zip(secret, guess):
            if s == g:
                bulls += 1
            else:
                s_count[int(s)] += 1
                g_count[int(g)] += 1
        cows = sum(min(s_count[i], g_count[i]) for i in range(10))
        return f'{bulls}A{cows}B'

