    const gCount = new Array(10).fill(0);
    for (let i = 0; i < secret.length; i++) {
        if (secret[i] === guess[i]) bulls++;
        else {
            sCount[+secret[i]]++;
            gCount[+guess[i]]++;
        }
    }
    let cows = 0;
    for (let i = 0; i < 10; i++) cows += Math.min(sCount[i], gCount[i]);
    return `${bulls}A${cows}B`;
};

