class Solution:
    def snakesAndLadders(self, board: List[List[int]]) -> int:
        n = len(board)
        def get_pos(s):
            r, c = divmod(s - 1, n)
            if r % 2 == 1:
                c = n - 1 - c
            return n - 1 - r, c
        visited = set()
        queue = [(1, 0)]
        visited.add(1)
        for sq, moves in queue:
            if sq == n * n:
                return moves
            for dice in range(1, 7):
                nxt = sq + dice
                if nxt > n * n:
                    continue
                r, c = get_pos(nxt)
                if board[r][c] != -1:
                    nxt = board[r][c]
                if nxt not in visited:
                    visited.add(nxt)
                    queue.append((nxt, moves + 1))
        return -1

