var snakesAndLadders = function(board) {
    const n = board.length;
    const getPos = (s) => {
        let r = Math.floor((s - 1) / n);
        let c = (s - 1) % n;
        if (r % 2 === 1) c = n - 1 - c;
        return [n - 1 - r, c];
    };
    const visited = new Set([1]);
    const queue = [[1, 0]];
    for (const [sq, moves] of queue) {
        if (sq === n * n) return moves;
        for (let dice = 1; dice <= 6; dice++) {
            let nxt = sq + dice;
            if (nxt > n * n) continue;
            const [r, c] = getPos(nxt);
            if (board[r][c] !== -1) nxt = board[r][c];
            if (!visited.has(nxt)) {
                visited.add(nxt);
                queue.push([nxt, moves + 1]);
            }
        }
    }
    return -1;
};

