class Solution:
    def openLock(self, deadends: List[str], target: str) -> int:
        dead = set(deadends)
        if '0000' in dead:
            return -1
        queue = [('0000', 0)]
        visited = {'0000'}
        for state, turns in queue:
            if state == target:
                return turns
            for i in range(4):
                d = int(state[i])
                for delta in (1, -1):
                    nd = (d + delta) % 10
                    nxt = state[:i] + str(nd) + state[i+1:]
                    if nxt not in visited and nxt not in dead:
                        visited.add(nxt)
                        queue.append((nxt, turns + 1))
        return -1

