    if (this.idxMap.has(val)) return false;
    this.idxMap.set(val, this.vals.length);
    this.vals.push(val);
    return true;
};
RandomizedSet.prototype.remove = function(val) {
    if (!this.idxMap.has(val)) return false;
    const idx = this.idxMap.get(val);
    const last = this.vals[this.vals.length - 1];
    this.vals[idx] = last;
