        const mid = (lo + hi) >> 1;
        if (this.events[mid][0] < start) lo = mid + 1;
        else hi = mid;
    }
    if (lo > 0 && this.events[lo-1][1] > start) return false;
    if (lo < this.events.length && this.events[lo][0] < end) return false;
    this.events.splice(lo, 0, [start, end]);
    return true;
};

