class Solution:
    def prisonAfterNDays(self, cells: List[int], n: int) -> List[int]:
        def next_day(c):
            return [0] + [1 if c[i-1] == c[i+1] else 0 for i in range(1, 7)] + [0]
        seen = {}
        day = 0
        while day < n:
            state = tuple(cells)
            if state in seen:
                cycle = day - seen[state]
                remaining = (n - day) % cycle
                for _ in range(remaining):
                    cells = next_day(cells)
                return cells
            seen[state] = day
            cells = next_day(cells)
            day += 1
        return cells

solution_js:
var prisonAfterNDays = function(cells, n) {
    const nextDay = (c) => {
        const res = [0,0,0,0,0,0,0,0];
        for (let i = 1; i < 7; i++) res[i] = c[i-1] === c[i+1] ? 1 : 0;
        return res;
    };
    const seen = new Map();
    let day = 0;
    while (day < n) {
        const key = cells.join('');
        if (seen.has(key)) {
            const cycle = day - seen.get(key);
            const remaining = (n - day) % cycle;
            for (let i = 0; i < remaining; i++) cells = nextDay(cells);
            return cells;
        }
        seen.set(key, day);
        cells = nextDay(cells);
        day++;
    }
    return cells;
};

