import heapq

class Solution:
    def trapRainWater(self, heightMap: List[List[int]]) -> int:
        if not heightMap or len(heightMap) < 3 or len(heightMap[0]) < 3:
            return 0
        m, n = len(heightMap), len(heightMap[0])
        visited = [[False]*n for _ in range(m)]
        heap = []
        for i in range(m):
            for j in range(n):
                if i == 0 or i == m-1 or j == 0 or j == n-1:
                    heapq.heappush(heap, (heightMap[i][j], i, j))
                    visited[i][j] = True
        water = 0
        while heap:
            h, r, c = heapq.heappop(heap)
            for dr, dc in ((0,1),(0,-1),(1,0),(-1,0)):
                nr, nc = r+dr, c+dc
                if 0 <= nr < m and 0 <= nc < n and not visited[nr][nc]:
                    visited[nr][nc] = True
                    water += max(0, h - heightMap[nr][nc])
                    heapq.heappush(heap, (max(h, heightMap[nr][nc]), nr, nc))
        return water

solution_js:
var trapRainWater = function(heightMap) {
    const m = heightMap.length, n = heightMap[0].length;
    if (m < 3 || n < 3) return 0;
    const visited = Array.from({length: m}, () => new Array(n).fill(false));
    const heap = []; // min-heap: [height, row, col]
    const push = (h, r, c) => { heap.push([h,r,c]); let i=heap.length-1; while(i>0){const p=(i-1)>>1; if(heap[p][0]<=heap[i][0])break; [heap[p],heap[i]]=[heap[i],heap[p]]; i=p;} };
    const pop = () => { const top=heap[0]; const last=heap.pop(); if(heap.length){heap[0]=last; let i=0; while(true){let s=i; const l=2*i+1,r=2*i+2; if(l<heap.length&&heap[l][0]<heap[s][0])s=l; if(r<heap.length&&heap[r][0]<heap[s][0])s=r; if(s===i)break; [heap[s],heap[i]]=[heap[i],heap[s]]; i=s;}} return top; };
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++)
        if (i===0||i===m-1||j===0||j===n-1) { push(heightMap[i][j],i,j); visited[i][j]=true; }
    let water = 0;
    while (heap.length) {
        const [h,r,c] = pop();
        for (const [dr,dc] of [[0,1],[0,-1],[1,0],[-1,0]]) {
            const nr=r+dr, nc=c+dc;
            if (nr>=0&&nr<m&&nc>=0&&nc<n&&!visited[nr][nc]) {
                visited[nr][nc]=true;
                water += Math.max(0, h-heightMap[nr][nc]);
                push(Math.max(h, heightMap[nr][nc]), nr, nc);
            }
        }
    }
    return water;
};

