class Solution:
    def findLadders(self, beginWord, endWord, wordList):
        word_set = set(wordList)
        if endWord not in word_set:
            return []
        dist = {beginWord: 0}
        queue = [beginWord]
        for word in queue:
            d = dist[word]
            for i in range(len(word)):
                for c in 'abcdefghijklmnopqrstuvwxyz':
                    nxt = word[:i] + c + word[i+1:]
                    if nxt in word_set and nxt not in dist:
                        dist[nxt] = d + 1
                        queue.append(nxt)
        if endWord not in dist:
            return []
        result = []
        def dfs(word, path):
            if word == beginWord:
                result.append(path[::-1])
                return
            for i in range(len(word)):
                for c in 'abcdefghijklmnopqrstuvwxyz':
                    prev = word[:i] + c + word[i+1:]
                    if prev in dist and dist[prev] == dist[word] - 1:
                        dfs(prev, path + [prev])
        dfs(endWord, [endWord])
        return result

solution_js:
var findLadders = function(beginWord, endWord, wordList) {
    const wordSet = new Set(wordList);
    if (!wordSet.has(endWord)) return [];
    const dist = new Map([[beginWord, 0]]);
    const queue = [beginWord];
    for (const word of queue) {
        const d = dist.get(word);
        for (let i = 0; i < word.length; i++) {
            for (let c = 97; c <= 122; c++) {
                const nxt = word.slice(0,i) + String.fromCharCode(c) + word.slice(i+1);
                if (wordSet.has(nxt) && !dist.has(nxt)) {
                    dist.set(nxt, d+1);
                    queue.push(nxt);
                }
            }
        }
    }
    if (!dist.has(endWord)) return [];
    const result = [];
    const dfs = (word, path) => {
        if (word === beginWord) { result.push([...path].reverse()); return; }
        for (let i = 0; i < word.length; i++) {
            for (let c = 97; c <= 122; c++) {
                const prev = word.slice(0,i) + String.fromCharCode(c) + word.slice(i+1);
                if (dist.has(prev) && dist.get(prev) === dist.get(word) - 1)
                    dfs(prev, [...path, prev]);
            }
        }
    };
    dfs(endWord, [endWord]);
    return result;
};

