class Solution:
    def boundaryOfBinaryTree(self, root: Optional[TreeNode]) -> List[int]:
        if not root:
            return []
        def is_leaf(n):
            return not n.left and not n.right
        left_bound = []
        node = root.left
        while node and not is_leaf(node):
            left_bound.append(node.val)
            node = node.left if node.left else node.right
        leaves = []
        def dfs(node):
            if not node:
                return
            if is_leaf(node):
                leaves.append(node.val)
                return
            dfs(node.left)
            dfs(node.right)
        dfs(root)
        right_bound = []
        node = root.right
        while node and not is_leaf(node):
            right_bound.append(node.val)
            node = node.right if node.right else node.left
        return [root.val] + left_bound + leaves + right_bound[::-1]

solution_js:
var boundaryOfBinaryTree = function(root) {
    if (!root) return [];
    const isLeaf = (n) => !n.left && !n.right;
    const leftBound = [];
    let node = root.left;
    while (node && !isLeaf(node)) {
        leftBound.push(node.val);
        node = node.left || node.right;
    }
    const leaves = [];
    const dfs = (n) => {
        if (!n) return;
        if (isLeaf(n)) { leaves.push(n.val); return; }
        dfs(n.left); dfs(n.right);
    };
    dfs(root);
    const rightBound = [];
    node = root.right;
    while (node && !isLeaf(node)) {
        rightBound.push(node.val);
        node = node.right || node.left;
    }
    return [root.val, ...leftBound, ...leaves, ...rightBound.reverse()];
};

