class Solution:
    def findUnsortedSubarray(self, nums: List[int]) -> int:
        n = len(nums)
        left, right = n, 0
        max_val = float('-inf')
        for i in range(n):
            if nums[i] < max_val:
                right = i
            max_val = max(max_val, nums[i])
        min_val = float('inf')
        for i in range(n - 1, -1, -1):
            if nums[i] > min_val:
                left = i
            min_val = min(min_val, nums[i])
        return right - left + 1 if right > left else 0

