    const n = nums.length;
    let left = n, right = 0;
    let maxVal = -Infinity;
    for (let i = 0; i < n; i++) {
        if (nums[i] < maxVal) right = i;
        maxVal = Math.max(maxVal, nums[i]);
    }
    let minVal = Infinity;
    for (let i = n - 1; i >= 0; i--) {
        if (nums[i] > minVal) left = i;
        minVal = Math.min(minVal, nums[i]);
    }
    return right > left ? right - left + 1 : 0;
};

