        if (!travel.has(i)) dp[i] = dp[i - 1];
        else dp[i] = Math.min(
            dp[i - 1] + costs[0],
            dp[Math.max(0, i - 7)] + costs[1],
            dp[Math.max(0, i - 30)] + costs[2]
        );
    }
    return dp[last];
};

