class Solution:
    def restoreIpAddresses(self, s: str) -> list[str]:
        result = []
        def backtrack(start, parts):
            if len(parts) == 4:
                if start == len(s):
                    result.append('.'.join(parts))
                return
            for length in range(1, 4):
                if start + length > len(s):
                    break
                segment = s[start:start + length]
                if (segment[0] == '0' and length > 1) or int(segment) > 255:
                    continue
                backtrack(start + length, parts + [segment])
        backtrack(0, [])
        return result

solution_js:
var restoreIpAddresses = function(s) {
    const result = [];
    function backtrack(start, parts) {
        if (parts.length === 4) {
            if (start === s.length) result.push(parts.join('.'));
            return;
        }
        for (let len = 1; len <= 3; len++) {
            if (start + len > s.length) break;
            const segment = s.substring(start, start + len);
            if ((segment[0] === '0' && len > 1) || Number(segment) > 255) continue;
            backtrack(start + len, [...parts, segment]);
        }
    }
    backtrack(0, []);
    return result;
};

