    let maxArea = 0;
    for (const row of matrix) {
        for (let j = 0; j < cols; j++) {
            heights[j] = row[j] === '1' ? heights[j] + 1 : 0;
        }
        const stack = [-1];
        for (let j = 0; j <= cols; j++) {
            while (stack[stack.length - 1] !== -1 && heights[stack[stack.length - 1]] >= heights[j]) {
                const h = heights[stack.pop()];
                const w = j - stack[stack.length - 1] - 1;
                maxArea = Math.max(maxArea, h * w);
            }
            stack.push(j);
        }
    }
    return maxArea;
};

var minEdgeReversals = function(n, edges) {
    const adj = Array.from({length: n}, () => []);
    for (const [u, v] of edges) {
        adj[u].push([v, 0]);
        adj[v].push([u, 1]);
    }
    const ans = new Array(n).fill(0);
    const parent = new Array(n).fill(-1);
    const costToParent = new Array(n).fill(0);
    const order = [];
    const stack = [[0, -1]];
    while (stack.length) {
        const [node, par] = stack.pop();
        order.push(node);
        parent[node] = par;
        for (const [nei, cost] of adj[node]) {
            if (nei !== par) {
                ans[0] += cost;
                costToParent[nei] = cost;
                stack.push([nei, node]);
            }
        }
    }
    for (const node of order) {
        if (parent[node] === -1) continue;
        ans[node] = ans[parent[node]] + (costToParent[node] === 0 ? 1 : -1);
    }
    return ans;
};

