        length++;
    }
    k %= length;
    if (k === 0) return head;
    tail.next = head;
    let newTail = head;
    for (let i = 0; i < length - k - 1; i++) {
        newTail = newTail.next;
    }
    const newHead = newTail.next;
    newTail.next = null;
    return newHead;
};

