        if (i < n) fact *= i;
    }
    k--;
    let result = '';
    for (let i = n; i > 0; i--) {
        const idx = Math.floor(k / fact);
        result += digits[idx];
        digits.splice(idx, 1);
        k %= fact;
        fact = i > 1 ? Math.floor(fact / (i - 1)) : 1;
    }
    return result;
};

