class Solution:
    def isBipartite(self, graph: list[list[int]]) -> bool:
        color = {}
        for node in range(len(graph)):
            if node in color:
                continue
            queue = [node]
            color[node] = 0
            while queue:
                curr = queue.pop(0)
                for nei in graph[curr]:
                    if nei not in color:
                        color[nei] = 1 - color[curr]
                        queue.append(nei)
                    elif color[nei] == color[curr]:
                        return False
        return True

