class Solution:
    def maxPalindromes(self, s: str, k: int) -> int:
        n = len(s)
        dp = [0] * (n + 1)
        def isPalin(l, r):
            while l < r:
                if s[l] != s[r]:
                    return False
                l += 1
                r -= 1
            return True
        for i in range(n):
            dp[i + 1] = dp[i]
            for length in [k, k + 1]:
                start = i - length + 1
                if start >= 0 and isPalin(start, i):
                    dp[i + 1] = max(dp[i + 1], dp[start] + 1)
                    break
        return dp[n]

solution_js:
var maxPalindromes = function(s, k) {
    const n = s.length;
    const dp = new Array(n + 1).fill(0);
    const isPalin = (l, r) => {
        while (l < r) {
            if (s[l] !== s[r]) return false;
            l++;
            r--;
        }
        return true;
    };
    for (let i = 0; i < n; i++) {
        dp[i + 1] = dp[i];
        for (const len of [k, k + 1]) {
            const start = i - len + 1;
            if (start >= 0 && isPalin(start, i)) {
                dp[i + 1] = Math.max(dp[i + 1], dp[start] + 1);
                break;
            }
        }
    }
    return dp[n];
};

