class Solution:
    def shiftingLetters(self, s: str, shifts: list[int]) -> str:
        n = len(s)
        total = 0
        result = list(s)
        for i in range(n - 1, -1, -1):
            total += shifts[i]
            result[i] = chr((ord(s[i]) - ord('a') + total) % 26 + ord('a'))
        return ''.join(result)

solution_js:
var shiftingLetters = function(s, shifts) {
    const n = s.length;
    const result = s.split('');
    let total = 0;
    for (let i = n - 1; i >= 0; i--) {
        total += shifts[i];
        result[i] = String.fromCharCode((s.charCodeAt(i) - 97 + total % 26) % 26 + 97);
    }
    return result.join('');
};

