class Solution:
    def twistedMirrorPathCount(self, grid: list[list[str]]) -> int:
        m, n = len(grid), len(grid[0])
        dirs = {'U': (-1, 0), 'D': (1, 0), 'L': (0, -1), 'R': (0, 1)}
        reflect = {
            '/': {'U': 'R', 'D': 'L', 'L': 'D', 'R': 'U'},
            '\\': {'U': 'L', 'D': 'R', 'L': 'U', 'R': 'D'}
        }
        count = 0
        entries = []
        for j in range(n):
            entries.append((0, j, 'D'))
            entries.append((m - 1, j, 'U'))
        for i in range(m):
            entries.append((i, 0, 'R'))
            entries.append((i, n - 1, 'L'))
        for r, c, d in entries:
            visited = set()
            while 0 <= r < m and 0 <= c < n:
                if (r, c, d) in visited:
                    break
                visited.add((r, c, d))
                if grid[r][c] in reflect:
                    d = reflect[grid[r][c]][d]
                dr, dc = dirs[d]
                r, c = r + dr, c + dc
            count += 1
        return count

solution_js:
var twistedMirrorPathCount = function(grid) {
    const m = grid.length, n = grid[0].length;
    const dirs = {'U': [-1, 0], 'D': [1, 0], 'L': [0, -1], 'R': [0, 1]};
    const reflect = {
        '/': {'U': 'R', 'D': 'L', 'L': 'D', 'R': 'U'},
        '\\': {'U': 'L', 'D': 'R', 'L': 'U', 'R': 'D'}
    };
    let count = 0;
    const entries = [];
    for (let j = 0; j < n; j++) {
        entries.push([0, j, 'D']);
        entries.push([m - 1, j, 'U']);
    }
    for (let i = 0; i < m; i++) {
        entries.push([i, 0, 'R']);
        entries.push([i, n - 1, 'L']);
    }
    for (const [sr, sc, sd] of entries) {
        let r = sr, c = sc, d = sd;
        const visited = new Set();
        while (r >= 0 && r < m && c >= 0 && c < n) {
            const key = `${r},${c},${d}`;
            if (visited.has(key)) break;
            visited.add(key);
            if (reflect[grid[r][c]]) d = reflect[grid[r][c]][d];
            const [dr, dc] = dirs[d];
            r += dr;
            c += dc;
        }
        count++;
    }
    return count;
};

