class Solution:
    def minMalwareSpread(self, graph: list[list[int]], initial: list[int]) -> int:
        n = len(graph)
        parent = list(range(n))
        size = [1] * n
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            a, b = find(a), find(b)
            if a == b:
                return
            if size[a] < size[b]:
                a, b = b, a
            parent[b] = a
            size[a] += size[b]
        for i in range(n):
            for j in range(i + 1, n):
                if graph[i][j] == 1:
                    union(i, j)
        from collections import Counter
        initial_set = set(initial)
        comp_count = Counter()
        for node in initial:
            comp_count[find(node)] += 1
        best = min(initial)
        best_save = 0
        for node in initial:
            root = find(node)
            if comp_count[root] == 1:
                saved = size[root]
                if saved > best_save or (saved == best_save and node < best):
                    best_save = saved
                    best = node
        return best

solution_js:
var minMalwareSpread = function(graph, initial) {
    const n = graph.length;
    const parent = Array.from({length: n}, (_, i) => i);
    const size = new Array(n).fill(1);
    const find = (x) => {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    };
    const union = (a, b) => {
        a = find(a); b = find(b);
        if (a === b) return;
        if (size[a] < size[b]) [a, b] = [b, a];
        parent[b] = a;
        size[a] += size[b];
    };
    for (let i = 0; i < n; i++)
        for (let j = i + 1; j < n; j++)
            if (graph[i][j] === 1) union(i, j);
    const compCount = {};
    for (const node of initial) {
        const r = find(node);
        compCount[r] = (compCount[r] || 0) + 1;
    }
    let best = Math.min(...initial), bestSave = 0;
    for (const node of initial) {
        const root = find(node);
        if (compCount[root] === 1) {
            const saved = size[root];
            if (saved > bestSave || (saved === bestSave && node < best)) {
                bestSave = saved;
                best = node;
            }
        }
    }
    return best;
};

