class Solution:
    def fullJustify(self, words: list[str], maxWidth: int) -> list[str]:
        result = []
        i = 0
        while i < len(words):
            line = [words[i]]
            length = len(words[i])
            i += 1
            while i < len(words) and length + 1 + len(words[i]) <= maxWidth:
                length += 1 + len(words[i])
                line.append(words[i])
                i += 1
            if i == len(words) or len(line) == 1:
                text = ' '.join(line)
                result.append(text + ' ' * (maxWidth - len(text)))
            else:
                total_spaces = maxWidth - sum(len(w) for w in line)
                gaps = len(line) - 1
                space, extra = divmod(total_spaces, gaps)
                text = ''
                for j, word in enumerate(line):
                    text += word
                    if j < gaps:
                        text += ' ' * (space + (1 if j < extra else 0))
                result.append(text)
        return result

solution_js:
var fullJustify = function(words, maxWidth) {
    const result = [];
    let i = 0;
    while (i < words.length) {
        const line = [words[i]];
        let length = words[i].length;
        i++;
        while (i < words.length && length + 1 + words[i].length <= maxWidth) {
            length += 1 + words[i].length;
            line.push(words[i]);
            i++;
        }
        if (i === words.length || line.length === 1) {
            const text = line.join(' ');
            result.push(text + ' '.repeat(maxWidth - text.length));
        } else {
            const totalSpaces = maxWidth - line.reduce((s, w) => s + w.length, 0);
            const gaps = line.length - 1;
            const space = Math.floor(totalSpaces / gaps);
            const extra = totalSpaces % gaps;
            let text = '';
            for (let j = 0; j < line.length; j++) {
                text += line[j];
                if (j < gaps) {
                    text += ' '.repeat(space + (j < extra ? 1 : 0));
                }
            }
            result.push(text);
        }
    }
    return result;
};

