class Solution:
    def spellchecker(self, wordlist: list[str], queries: list[str]) -> list[str]:
        def devowel(w):
            return ''.join('*' if c in 'aeiou' else c for c in w.lower())
        exact = set(wordlist)
        cap_map = {}
        vowel_map = {}
        for w in wordlist:
            lo = w.lower()
            if lo not in cap_map:
                cap_map[lo] = w
            dv = devowel(w)
            if dv not in vowel_map:
                vowel_map[dv] = w
        result = []
        for q in queries:
            if q in exact:
                result.append(q)
            elif q.lower() in cap_map:
                result.append(cap_map[q.lower()])
            elif devowel(q) in vowel_map:
                result.append(vowel_map[devowel(q)])
            else:
                result.append('')
        return result

solution_js:
var spellchecker = function(wordlist, queries) {
    const devowel = (w) => w.toLowerCase().replace(/[aeiou]/g, '*');
    const exact = new Set(wordlist);
    const capMap = new Map();
    const vowelMap = new Map();
    for (const w of wordlist) {
        const lo = w.toLowerCase();
        if (!capMap.has(lo)) capMap.set(lo, w);
        const dv = devowel(w);
        if (!vowelMap.has(dv)) vowelMap.set(dv, w);
    }
    return queries.map(q => {
        if (exact.has(q)) return q;
        const lo = q.toLowerCase();
        if (capMap.has(lo)) return capMap.get(lo);
        const dv = devowel(q);
        if (vowelMap.has(dv)) return vowelMap.get(dv);
        return '';
    });
};

var cleanRoom = function(robot) {
    const directions = [[-1, 0], [0, 1], [1, 0], [0, -1]];
    const visited = new Set();
    const goBack = () => {
        robot.turnRight();
        robot.turnRight();
        robot.move();
        robot.turnRight();
        robot.turnRight();
    };
    const dfs = (x, y, d) => {
        visited.add(`${x},${y}`);
        robot.clean();
        for (let i = 0; i < 4; i++) {
            const nd = (d + i) % 4;
            const nx = x + directions[nd][0];
            const ny = y + directions[nd][1];
            if (!visited.has(`${nx},${ny}`) && robot.move()) {
                dfs(nx, ny, nd);
                goBack();
            }
            robot.turnRight();
        }
    };
    dfs(0, 0, 0);
};

