class Solution:
    def minimumOperations(self, nums: list[int], target: list[int]) -> int:
        n = len(nums)
        diff = [target[i] - nums[i] for i in range(n)]
        ops = abs(diff[0])
        for i in range(1, n):
            if diff[i] > 0 and diff[i - 1] >= 0:
                ops += max(0, diff[i] - diff[i - 1])
            elif diff[i] < 0 and diff[i - 1] <= 0:
                ops += max(0, abs(diff[i]) - abs(diff[i - 1]))
            else:
                ops += abs(diff[i])
        return ops

solution_js:
var minimumOperations = function(nums, target) {
    const n = nums.length;
    const diff = nums.map((v, i) => target[i] - v);
    let ops = Math.abs(diff[0]);
    for (let i = 1; i < n; i++) {
        if (diff[i] > 0 && diff[i - 1] >= 0) {
            ops += Math.max(0, diff[i] - diff[i - 1]);
        } else if (diff[i] < 0 && diff[i - 1] <= 0) {
            ops += Math.max(0, Math.abs(diff[i]) - Math.abs(diff[i - 1]));
        } else {
            ops += Math.abs(diff[i]);
        }
    }
    return ops;
};

