class Solution:
    def maximalNetworkRank(self, n: int, roads: list[list[int]]) -> int:
        degree = [0] * n
        edges = set()
        for a, b in roads:
            degree[a] += 1
            degree[b] += 1
            edges.add((min(a, b), max(a, b)))
        max_rank = 0
        for i in range(n):
            for j in range(i + 1, n):
                rank = degree[i] + degree[j]
                if (i, j) in edges:
                    rank -= 1
                max_rank = max(max_rank, rank)
        return max_rank

