class Solution:
    def largestIsland(self, grid: List[List[int]]) -> int:
        n = len(grid)
        island_id = 2
        size = {}
        def dfs(r, c, iid):
            if r < 0 or r >= n or c < 0 or c >= n or grid[r][c] != 1:
                return 0
            grid[r][c] = iid
            return 1 + dfs(r+1,c,iid) + dfs(r-1,c,iid) + dfs(r,c+1,iid) + dfs(r,c-1,iid)
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 1:
                    size[island_id] = dfs(i, j, island_id)
                    island_id += 1
        if not size:
            return 1
        res = max(size.values())
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 0:
                    seen = set()
                    total = 1
                    for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
                        ni, nj = i+dr, j+dc
                        if 0 <= ni < n and 0 <= nj < n and grid[ni][nj] > 1 and grid[ni][nj] not in seen:
                            seen.add(grid[ni][nj])
                            total += size[grid[ni][nj]]
                    res = max(res, total)
        return res

