var largestIsland = function(grid) {
    const n = grid.length;
    let islandId = 2;
    const size = {};
    const dfs = (r, c, id) => {
        if (r < 0 || r >= n || c < 0 || c >= n || grid[r][c] !== 1) return 0;
        grid[r][c] = id;
        return 1 + dfs(r+1,c,id) + dfs(r-1,c,id) + dfs(r,c+1,id) + dfs(r,c-1,id);
    };
    for (let i = 0; i < n; i++)
        for (let j = 0; j < n; j++)
            if (grid[i][j] === 1) { size[islandId] = dfs(i, j, islandId); islandId++; }
    if (Object.keys(size).length === 0) return 1;
    let res = Math.max(...Object.values(size));
    const dirs = [[0,1],[0,-1],[1,0],[-1,0]];
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 0) {
                const seen = new Set();
                let total = 1;
                for (const [dr,dc] of dirs) {
                    const ni = i+dr, nj = j+dc;
                    if (ni >= 0 && ni < n && nj >= 0 && nj < n && grid[ni][nj] > 1 && !seen.has(grid[ni][nj])) {
                        seen.add(grid[ni][nj]);
                        total += size[grid[ni][nj]];
                    }
                }
                res = Math.max(res, total);
            }
        }
    }
    return res;
};

