class Solution:
    def numberOfSequence(self, n: int, sick: List[int]) -> int:
        MOD = 10**9 + 7
        gaps = []
        if sick[0] > 0:
            gaps.append(sick[0])
        for i in range(1, len(sick)):
            g = sick[i] - sick[i-1] - 1
            if g > 0:
                gaps.append(g)
        if sick[-1] < n - 1:
            gaps.append(n - 1 - sick[-1])
        total = sum(gaps)
        if total == 0:
            return 1
        # Precompute factorials
        fact = [1] * (total + 1)
        for i in range(1, total + 1):
            fact[i] = fact[i-1] * i % MOD
        inv_fact = [1] * (total + 1)
        inv_fact[total] = pow(fact[total], MOD - 2, MOD)
        for i in range(total - 1, -1, -1):
            inv_fact[i] = inv_fact[i+1] * (i+1) % MOD
        res = fact[total]
        for g in gaps:
            res = res * inv_fact[g] % MOD
        # Middle gaps get 2^(g-1) factor
        start = 1 if sick[0] > 0 else 0
        end = len(gaps) - 1 if sick[-1] < n - 1 else len(gaps)
        for i in range(start, end):
            if gaps[i] > 1:
                res = res * pow(2, gaps[i] - 1, MOD) % MOD
        return res

solution_js:
var numberOfSequence = function(n, sick) {
    const MOD = 1000000007n;
    const gaps = [];
    if (sick[0] > 0) gaps.push(sick[0]);
    for (let i = 1; i < sick.length; i++) {
        const g = sick[i] - sick[i-1] - 1;
        if (g > 0) gaps.push(g);
    }
    if (sick[sick.length-1] < n - 1) gaps.push(n - 1 - sick[sick.length-1]);
    const total = gaps.reduce((a, b) => a + b, 0);
    if (total === 0) return 1;
    const fact = [1n];
    for (let i = 1; i <= total; i++) fact[i] = fact[i-1] * BigInt(i) % MOD;
    const modpow = (base, exp, mod) => {
        let result = 1n; base = base % mod;
        while (exp > 0n) { if (exp % 2n === 1n) result = result * base % mod; exp /= 2n; base = base * base % mod; }
        return result;
    };
    const invFact = new Array(total + 1);
    invFact[total] = modpow(fact[total], MOD - 2n, MOD);
    for (let i = total - 1; i >= 0; i--) invFact[i] = invFact[i+1] * BigInt(i+1) % MOD;
    let res = fact[total];
    for (const g of gaps) res = res * invFact[g] % MOD;
    const start = sick[0] > 0 ? 1 : 0;
    const end = sick[sick.length-1] < n - 1 ? gaps.length - 1 : gaps.length;
    for (let i = start; i < end; i++) {
        if (gaps[i] > 1) res = res * modpow(2n, BigInt(gaps[i] - 1), MOD) % MOD;
    }
    return Number(res);
};

