    let count = 0;
    for (let i = 0; i < this.mem.length; i++) {
        if (this.mem[i] === 0) {
            count++;
            if (count === size) {
                for (let j = i - size + 1; j <= i; j++) this.mem[j] = mID;
                return i - size + 1;
            }
        } else {
            count = 0;
        }
    }
    return -1;
};

Allocator.prototype.free = function(mID) {
    let count = 0;
    for (let i = 0; i < this.mem.length; i++) {
        if (this.mem[i] === mID) { this.mem[i] = 0; count++; }
    }
    return count;
};

