class Solution:
    def minRefuelStops(self, target: int, startFuel: int, stations: List[List[int]]) -> int:
        heap = []
        fuel = startFuel
        stops = 0
        prev = 0
        for pos, gas in stations + [[target, 0]]:
            fuel -= (pos - prev)
            while heap and fuel < 0:
