class Solution:
    def minMutation(self, startGene: str, endGene: str, bank: list[str]) -> int:
        bank_set = set(bank)
        if endGene not in bank_set:
            return -1
        from collections import deque
        queue = deque([(startGene, 0)])
        visited = {startGene}
        while queue:
            gene, steps = queue.popleft()
            if gene == endGene:
                return steps
            for i in range(len(gene)):
                for c in 'ACGT':
                    if c != gene[i]:
                        mutated = gene[:i] + c + gene[i+1:]
                        if mutated in bank_set and mutated not in visited:
                            visited.add(mutated)
                            queue.append((mutated, steps + 1))
        return -1

solution_js:
var minMutation = function(startGene, endGene, bank) {
    const bankSet = new Set(bank);
    if (!bankSet.has(endGene)) return -1;
    const visited = new Set([startGene]);
    const queue = [[startGene, 0]];
    while (queue.length) {
        const [gene, steps] = queue.shift();
        if (gene === endGene) return steps;
        for (let i = 0; i < gene.length; i++) {
            for (const c of 'ACGT') {
                if (c !== gene[i]) {
                    const mutated = gene.slice(0, i) + c + gene.slice(i + 1);
                    if (bankSet.has(mutated) && !visited.has(mutated)) {
                        visited.add(mutated);
                        queue.push([mutated, steps + 1]);
                    }
                }
            }
        }
    }
    return -1;
};

