class Solution:
    def maximumOr(self, nums: list[int], k: int) -> int:
        n = len(nums)
        suffix = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            suffix[i] = suffix[i + 1] | nums[i]
        result = 0
        prefix = 0
        for i in range(n):
            result = max(result, prefix | (nums[i] << k) | suffix[i + 1])
            prefix |= nums[i]
        return result

solution_js:
var maximumOr = function(nums, k) {
    const n = nums.length;
    const suffix = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        suffix[i] = suffix[i + 1] | nums[i];
    }
    let result = 0n;
    let prefix = 0n;
    const bk = BigInt(k);
    for (let i = 0; i < n; i++) {
        const val = prefix | (BigInt(nums[i]) << bk) | BigInt(suffix[i + 1]);
        if (val > result) result = val;
        prefix |= BigInt(nums[i]);
    }
    return Number(result);
};

