class Solution:
    def totalNQueens(self, n: int) -> int:
        def backtrack(row, cols, diags, anti_diags):
            if row == n:
                return 1
            count = 0
            for col in range(n):
                if col in cols or (row - col) in diags or (row + col) in anti_diags:
                    continue
                cols.add(col)
                diags.add(row - col)
                anti_diags.add(row + col)
                count += backtrack(row + 1, cols, diags, anti_diags)
                cols.remove(col)
                diags.remove(row - col)
                anti_diags.remove(row + col)
            return count
        return backtrack(0, set(), set(), set())

solution_js:
var totalNQueens = function(n) {
    let count = 0;
    const cols = new Set(), diags = new Set(), antiDiags = new Set();
    function backtrack(row) {
        if (row === n) {
            count++;
            return;
        }
        for (let col = 0; col < n; col++) {
            if (cols.has(col) || diags.has(row - col) || antiDiags.has(row + col)) continue;
            cols.add(col);
            diags.add(row - col);
            antiDiags.add(row + col);
            backtrack(row + 1);
            cols.delete(col);
            diags.delete(row - col);
            antiDiags.delete(row + col);
        }
    }
    backtrack(0);
    return count;
};

