        graph[u].push(v);
        graph[v].push(u);
    }
    const visited = new Set([source]);
    const queue = [source];
    let i = 0;
    while (i < queue.length) {
        const node = queue[i++];
        if (node === destination) return true;
        for (const nei of graph[node]) {
            if (!visited.has(nei)) {
                visited.add(nei);
                queue.push(nei);
