class Solution:
    def maxPowerGridCount(self, n: int, edges: List[List[int]], queries: List[int]) -> List[int]:
        graph = defaultdict(set)
        for u, v in edges:
            graph[u].add(v)
            graph[v].add(u)
        result = []
        for q in queries:
            visited = set([q])
            count = 0
            for start in range(n):
                if start not in visited:
                    queue = deque([start])
                    visited.add(start)
                    comp = 0
                    while queue:
                        node = queue.popleft()
                        comp += 1
                        for nei in graph[node]:
                            if nei not in visited:
                                visited.add(nei)
                                queue.append(nei)
                    count = max(count, comp)
            result.append(count)
        return result

