        dp.set(word, 1);
        for (let i = 0; i < word.length; i++) {
            const pred = word.slice(0, i) + word.slice(i + 1);
            if (dp.has(pred)) {
                dp.set(word, Math.max(dp.get(word), dp.get(pred) + 1));
            }
        }
        ans = Math.max(ans, dp.get(word));
    }
    return ans;
};

