        def is_palindrome(s, lo, hi):
            while lo < hi:
                if s[lo] != s[hi]:
                    return False
                lo += 1
                hi -= 1
            return True
        word_map = {w[::-1]: i for i, w in enumerate(words)}
        result = []
        for i, word in enumerate(words):
            n = len(word)
            for j in range(n + 1):
                prefix = word[:j]
                suffix = word[j:]
                if prefix in word_map and word_map[prefix] != i and is_palindrome(word, j, n - 1):
                    result.append([i, word_map[prefix]])
                if j > 0 and suffix in word_map and word_map[suffix] != i and is_palindrome(word, 0, j - 1):
                    result.append([word_map[suffix], i])
        return result

