        if (hi - lo <= 1) return;
        const mid = (lo + hi) >> 1;
        mergeSort(lo, mid);
        mergeSort(mid, hi);
        const temp = [];
        let i = lo, j = mid;
        while (i < mid && j < hi) {
            if (nums[indices[j]] < nums[indices[i]]) {
                temp.push(indices[j++]);
            } else {
                counts[indices[i]] += j - mid;
                temp.push(indices[i++]);
            }
        }
        while (i < mid) {
            counts[indices[i]] += j - mid;
            temp.push(indices[i++]);
        }
        while (j < hi) temp.push(indices[j++]);
        for (let k = lo; k < hi; k++) indices[k] = temp[k - lo];
    }
    mergeSort(0, n);
    return counts;
};

