class Solution:
    def countMentions(self, numberOfUsers: int, events: list[list[str]]) -> list[int]:
        events.sort(key=lambda e: (int(e[1]), 0 if e[0] == 'OFFLINE' else 1))
        mentions = [0] * numberOfUsers
        online_time = [0] * numberOfUsers
        for event in events:
            typ, ts_str, msg = event
            ts = int(ts_str)
            if typ == 'OFFLINE':
                user_id = int(msg)
                online_time[user_id] = ts + 60
            elif typ == 'MESSAGE':
                if msg == 'ALL':
                    for i in range(numberOfUsers):
                        mentions[i] += 1
                elif msg == 'HERE':
                    for i in range(numberOfUsers):
                        if online_time[i] <= ts:
                            mentions[i] += 1
                else:
                    for uid_str in msg.split():
                        uid = int(uid_str[2:])
                        mentions[uid] += 1
        return mentions

solution_js:
var countMentions = function(numberOfUsers, events) {
    events.sort((a, b) => {
        const ta = parseInt(a[1]), tb = parseInt(b[1]);
        if (ta !== tb) return ta - tb;
        return (a[0] === 'OFFLINE' ? 0 : 1) - (b[0] === 'OFFLINE' ? 0 : 1);
    });
    const mentions = new Array(numberOfUsers).fill(0);
    const onlineTime = new Array(numberOfUsers).fill(0);
    for (const [typ, tsStr, msg] of events) {
        const ts = parseInt(tsStr);
        if (typ === 'OFFLINE') {
            const uid = parseInt(msg);
            onlineTime[uid] = ts + 60;
        } else if (typ === 'MESSAGE') {
            if (msg === 'ALL') {
                for (let i = 0; i < numberOfUsers; i++) mentions[i]++;
            } else if (msg === 'HERE') {
                for (let i = 0; i < numberOfUsers; i++) {
                    if (onlineTime[i] <= ts) mentions[i]++;
                }
            } else {
                for (const part of msg.split(' ')) {
                    const uid = parseInt(part.substring(2));
                    mentions[uid]++;
                }
            }
        }
    }
    return mentions;
};

