        for i in range(n):
            for j in range(n):
                if i != j:
                    dx = bombs[i][0] - bombs[j][0]
                    dy = bombs[i][1] - bombs[j][1]
                    if dx * dx + dy * dy <= bombs[i][2] * bombs[i][2]:
                        graph[i].append(j)
        best = 0
        for i in range(n):
            visited = set([i])
            queue = [i]
            while queue:
                node = queue.pop()
                for nei in graph[node]:
                    if nei not in visited:
                        visited.add(nei)
                        queue.append(nei)
            best = max(best, len(visited))
        return best

