        const c = s[i];
        const swap = c === c.toLowerCase() ? c.toUpperCase() : c.toLowerCase();
        if (!charSet.has(swap)) {
            const left = longestNiceSubstring(s.substring(0, i));
            const right = longestNiceSubstring(s.substring(i + 1));
            return left.length >= right.length ? left : right;
        }
    }
    return s;
};

