 */

var guessNumber = function(n) {
    let lo = 1, hi = n;
    while (lo <= hi) {
        const mid = Math.floor((lo + hi) / 2);
        const res = guess(mid);
        if (res === 0) return mid;
        else if (res === -1) hi = mid - 1;
        else lo = mid + 1;
    }
    return -1;
};

