var gcdOfSums = function(nums) {
    let evenSum = 0, oddSum = 0;
    for (let i = 0; i < nums.length; i++) {
        if (i % 2 === 0) evenSum += nums[i];
        else oddSum += nums[i];
    }
    if (evenSum === 0 || oddSum === 0) return 0;
    function gcd(a, b) {
        while (b) {
            [a, b] = [b, a % b];
        }
        return a;
    }
    return gcd(evenSum, oddSum);
};

