var binarySearchableNumbers = function(nums) {
    const n = nums.length;
    if (n === 0) return 0;
    const prefixMax = new Array(n).fill(-Infinity);
    const suffixMin = new Array(n).fill(Infinity);
    for (let i = 1; i < n; i++) {
        prefixMax[i] = Math.max(prefixMax[i - 1], nums[i - 1]);
    }
    for (let i = n - 2; i >= 0; i--) {
        suffixMin[i] = Math.min(suffixMin[i + 1], nums[i + 1]);
    }
    let count = 0;
    for (let i = 0; i < n; i++) {
        if (nums[i] > prefixMax[i] && nums[i] < suffixMin[i]) count++;
    }
    return count;
};

