class Solution:
    def minimumTimeRequired(self, jobs: list[int], k: int) -> int:
        jobs.sort(reverse=True)
        workers = [0] * k
        self.ans = sum(jobs)

        def backtrack(idx):
            if idx == len(jobs):
                self.ans = min(self.ans, max(workers))
                return
            seen = set()
            for i in range(k):
                if workers[i] + jobs[idx] >= self.ans:
                    continue
                if workers[i] in seen:
                    continue
                seen.add(workers[i])
                workers[i] += jobs[idx]
                backtrack(idx + 1)
                workers[i] -= jobs[idx]

        backtrack(0)
        return self.ans

