class Solution:
    def largestComponentSize(self, nums: list[int]) -> int:
        parent = {}
        def find(x):
            if x not in parent:
                parent[x] = x
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        for num in nums:
            d = 2
            temp = num
            while d * d <= temp:
                if temp % d == 0:
                    union(num, d)
                    while temp % d == 0:
                        temp //= d
                d += 1
            if temp > 1:
                union(num, temp)
        from collections import Counter
        count = Counter(find(num) for num in nums)
        return max(count.values())

