class Solution:
    def medianSlidingWindow(self, nums: list[int], k: int) -> list[float]:
        from sortedcontainers import SortedList
        window = SortedList()
        result = []
        for i in range(len(nums)):
            window.add(nums[i])
            if len(window) > k:
                window.remove(nums[i - k])
            if len(window) == k:
                if k % 2 == 1:
                    result.append(float(window[k // 2]))
                else:
                    result.append((window[k // 2 - 1] + window[k // 2]) / 2.0)
        return result

solution_js:
var medianSlidingWindow = function(nums, k) {
    const result = [];
    const win = nums.slice(0, k).map((v, i) => [v, i]);
    win.sort((a, b) => a[0] - b[0] || a[1] - b[1]);
    const getMedian = () => {
        if (k % 2 === 1) return win[Math.floor(k / 2)][0];
        return (win[Math.floor(k / 2) - 1][0] + win[Math.floor(k / 2)][0]) / 2;
    };
    const binaryInsert = (arr, val) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = Math.floor((lo + hi) / 2);
            if (arr[mid][0] < val[0] || (arr[mid][0] === val[0] && arr[mid][1] < val[1])) lo = mid + 1;
            else hi = mid;
        }
        arr.splice(lo, 0, val);
    };
    const binaryRemove = (arr, val) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = Math.floor((lo + hi) / 2);
            if (arr[mid][0] < val[0] || (arr[mid][0] === val[0] && arr[mid][1] < val[1])) lo = mid + 1;
            else hi = mid;
        }
        arr.splice(lo, 1);
    };
    result.push(getMedian());
    for (let i = k; i < nums.length; i++) {
        binaryRemove(win, [nums[i - k], i - k]);
        binaryInsert(win, [nums[i], i]);
        result.push(getMedian());
    }
    return result;
};

