class Solution:
    def longestIdealString(self, s: str, k: int) -> int:
        dp = [0] * 26
        for ch in s:
            idx = ord(ch) - ord('a')
            best = 0
            for j in range(max(0, idx - k), min(26, idx + k + 1)):
                best = max(best, dp[j])
            dp[idx] = best + 1
        return max(dp)

solution_js:
var longestIdealString = function(s, k) {
    const dp = new Array(26).fill(0);
    for (const ch of s) {
        const idx = ch.charCodeAt(0) - 97;
        let best = 0;
        for (let j = Math.max(0, idx - k); j <= Math.min(25, idx + k); j++) {
            best = Math.max(best, dp[j]);
        }
        dp[idx] = best + 1;
    }
    return Math.max(...dp);
};

