class Solution:
    def slidingPuzzle(self, board: list[list[int]]) -> int:
        start = ''.join(str(c) for row in board for c in row)
        target = '123450'
        if start == target:
            return 0
        neighbors = {0:[1,3], 1:[0,2,4], 2:[1,5], 3:[0,4], 4:[1,3,5], 5:[2,4]}
        from collections import deque
        queue = deque([(start, 0)])
        visited = {start}
        while queue:
            state, moves = queue.popleft()
            zero = state.index('0')
            for nei in neighbors[zero]:
                new_state = list(state)
                new_state[zero], new_state[nei] = new_state[nei], new_state[zero]
                new_s = ''.join(new_state)
                if new_s == target:
                    return moves + 1
                if new_s not in visited:
                    visited.add(new_s)
                    queue.append((new_s, moves + 1))
        return -1

solution_js:
var slidingPuzzle = function(board) {
    const start = board.flat().join('');
    const target = '123450';
    if (start === target) return 0;
    const neighbors = [[1,3],[0,2,4],[1,5],[0,4],[1,3,5],[2,4]];
    const queue = [[start, 0]];
    const visited = new Set([start]);
    while (queue.length) {
        const [state, moves] = queue.shift();
        const zero = state.indexOf('0');
        for (const nei of neighbors[zero]) {
            const arr = state.split('');
            [arr[zero], arr[nei]] = [arr[nei], arr[zero]];
            const newState = arr.join('');
            if (newState === target) return moves + 1;
            if (!visited.has(newState)) {
                visited.add(newState);
                queue.push([newState, moves + 1]);
            }
        }
    }
    return -1;
};

