class Solution:
    def threeSumClosest(self, nums: list[int], target: int) -> int:
        nums.sort()
        closest = float('inf')
        for i in range(len(nums) - 2):
            lo, hi = i + 1, len(nums) - 1
            while lo < hi:
                total = nums[i] + nums[lo] + nums[hi]
                if abs(total - target) < abs(closest - target):
                    closest = total
                if total < target:
                    lo += 1
                elif total > target:
                    hi -= 1
                else:
                    return total
        return closest

