        let lo = i + 1, hi = nums.length - 1;
        while (lo < hi) {
            const total = nums[i] + nums[lo] + nums[hi];
            if (Math.abs(total - target) < Math.abs(closest - target)) closest = total;
            if (total < target) lo++;
            else if (total > target) hi--;
            else return total;
        }
    }
    return closest;
};

