            const x2 = Math.min(topRight[i][0], topRight[j][0]);
            const y2 = Math.min(topRight[i][1], topRight[j][1]);
            if (x1 < x2 && y1 < y2) {
                const side = Math.min(x2 - x1, y2 - y1);
                best = Math.max(best, side * side);
