    for (let i = 0; i < s.length; i++) {
        if (inStack.has(s[i])) continue;
        while (stack.length && s[i] < stack[stack.length - 1] && last[stack[stack.length - 1]] > i) {
            inStack.delete(stack.pop());
        }
        stack.push(s[i]);
        inStack.add(s[i]);
    }
    return stack.join('');
};

