class Solution:
    def nthSuperUglyNumber(self, n: int, primes: list[int]) -> int:
        dp = [1] * n
        k = len(primes)
        pointers = [0] * k
        for i in range(1, n):
            candidates = [primes[j] * dp[pointers[j]] for j in range(k)]
            dp[i] = min(candidates)
            for j in range(k):
                if candidates[j] == dp[i]:
                    pointers[j] += 1
        return dp[-1]

solution_js:
var nthSuperUglyNumber = function(n, primes) {
    const dp = new Array(n).fill(1);
    const pointers = new Array(primes.length).fill(0);
    for (let i = 1; i < n; i++) {
        let min = Infinity;
        for (let j = 0; j < primes.length; j++) {
            min = Math.min(min, primes[j] * dp[pointers[j]]);
        }
        dp[i] = min;
        for (let j = 0; j < primes.length; j++) {
            if (primes[j] * dp[pointers[j]] === min) pointers[j]++;
        }
    }
    return dp[n - 1];
};

