class Solution:
    def minBitwiseArray(self, nums: list[int]) -> list[int]:
        result = []
        for num in nums:
            if num == 1:
                result.append(-1)
                continue
            # Find lowest 0 bit
            bit = 0
            while num & (1 << bit):
                bit += 1
            # Clear the bit just below the lowest 0
            result.append(num ^ (1 << (bit - 1)))
        return result

