class Solution:
    def calculate(self, s: str) -> int:
        def helper(it):
            stack = []
            num = 0
            op = '+'
            while True:
                ch = next(it, None)
                if ch is not None and ch.isdigit():
                    num = num * 10 + int(ch)
                if ch == '(':
                    num = helper(it)
                if ch is None or (ch in '+-*/)' and not ch.isdigit()):
                    if op == '+':
                        stack.append(num)
                    elif op == '-':
                        stack.append(-num)
                    elif op == '*':
                        stack.append(stack.pop() * num)
                    elif op == '/':
                        stack.append(int(stack.pop() / num))
                    num = 0
                    op = ch
                if ch is None or ch == ')':
                    break
            return sum(stack)
        return helper(iter(s.replace(' ', '')))

