        let lo = 0, hi = heaters.length - 1;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (heaters[mid] < h) lo = mid + 1;
            else hi = mid;
        }
        let dist = Math.abs(heaters[lo] - h);
        if (lo > 0) dist = Math.min(dist, Math.abs(h - heaters[lo - 1]));
        res = Math.max(res, dist);
    }
    return res;
};

