class Solution:
    def validTicTacToe(self, board: list[str]) -> bool:
        def wins(b, ch):
            for i in range(3):
                if all(b[i][j] == ch for j in range(3)):
                    return True
                if all(b[j][i] == ch for j in range(3)):
                    return True
            if b[0][0] == b[1][1] == b[2][2] == ch:
                return True
            if b[0][2] == b[1][1] == b[2][0] == ch:
                return True
            return False
        xc = sum(row.count('X') for row in board)
        oc = sum(row.count('O') for row in board)
        if xc != oc and xc != oc + 1:
            return False
        xw = wins(board, 'X')
        ow = wins(board, 'O')
        if xw and ow:
            return False
        if xw and xc == oc:
            return False
        if ow and xc != oc:
            return False
        return True

