    function wins(b, ch) {
        for (let i = 0; i < 3; i++) {
            if (b[i][0] === ch && b[i][1] === ch && b[i][2] === ch) return true;
            if (b[0][i] === ch && b[1][i] === ch && b[2][i] === ch) return true;
        }
        if (b[0][0] === ch && b[1][1] === ch && b[2][2] === ch) return true;
        if (b[0][2] === ch && b[1][1] === ch && b[2][0] === ch) return true;
        return false;
    }
    let xc = 0, oc = 0;
    for (const row of board) for (const c of row) { if (c === 'X') xc++; if (c === 'O') oc++; }
    if (xc !== oc && xc !== oc + 1) return false;
    const xw = wins(board, 'X'), ow = wins(board, 'O');
    if (xw && ow) return false;
    if (xw && xc === oc) return false;
    if (ow && xc !== oc) return false;
    return true;
};

