class Solution:
    def numDistinctIslands(self, grid: list[list[int]]) -> int:
        rows, cols = len(grid), len(grid[0])
        visited = set()
        shapes = set()
        def dfs(r, c, r0, c0, shape):
            if r < 0 or r >= rows or c < 0 or c >= cols:
                return
            if (r, c) in visited or grid[r][c] == 0:
                return
            visited.add((r, c))
            shape.append((r - r0, c - c0))
            for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
                dfs(r + dr, c + dc, r0, c0, shape)
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 1 and (r, c) not in visited:
                    shape = []
                    dfs(r, c, r, c, shape)
                    shapes.add(tuple(shape))
        return len(shapes)

solution_js:
var numDistinctIslands = function(grid) {
    const rows = grid.length, cols = grid[0].length;
    const visited = new Set();
    const shapes = new Set();
    function dfs(r, c, r0, c0, shape) {
        if (r < 0 || r >= rows || c < 0 || c >= cols) return;
        const key = r * cols + c;
        if (visited.has(key) || grid[r][c] === 0) return;
        visited.add(key);
        shape.push((r - r0) + ',' + (c - c0));
        dfs(r + 1, c, r0, c0, shape);
        dfs(r - 1, c, r0, c0, shape);
        dfs(r, c + 1, r0, c0, shape);
        dfs(r, c - 1, r0, c0, shape);
    }
    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            if (grid[r][c] === 1 && !visited.has(r * cols + c)) {
                const shape = [];
                dfs(r, c, r, c, shape);
                shapes.add(shape.join('|'));
            }
        }
    }
    return shapes.size;
};

