        const right = Math.min(n, i + ranges[i]);
        maxReach[left] = Math.max(maxReach[left], right);
    }
    let taps = 0, curEnd = 0, farEnd = 0;
    for (let i = 0; i <= n; i++) {
        if (i > farEnd) return -1;
        farEnd = Math.max(farEnd, maxReach[i]);
        if (i === curEnd && i < n) {
            taps++;
            curEnd = farEnd;
        }
    }
    return taps;
};

