class Solution:
    def minCost(self, n: int, edges: list[list[int]]) -> list[int]:
        from collections import defaultdict, deque
        graph = defaultdict(list)
        for u, v in edges:
            graph[u].append((v, 0))
            graph[v].append((u, 1))
        dist = [float('inf')] * n
        dist[0] = 0
        dq = deque([0])
        while dq:
            u = dq.popleft()
            for v, w in graph[u]:
                if dist[u] + w < dist[v]:
                    dist[v] = dist[u] + w
                    if w == 0:
                        dq.appendleft(v)
                    else:
                        dq.append(v)
        return dist

