        graph[v].push([u, 1]);
    }
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;
    const dq = [0];
    while (dq.length) {
        const u = dq.shift();
        for (const [v, w] of graph[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                if (w === 0) dq.unshift(v);
                else dq.push(v);
            }
        }
    }
    return dist;
};

