        const [pos, speed] = cars[i];
        while (stack.length) {
            const j = stack[stack.length - 1];
            if (speed <= cars[j][1]) {
                stack.pop();
            } else {
                const t = (cars[j][0] - pos) / (speed - cars[j][1]);
                if (res[j] < 0 || t <= res[j]) {
                    res[i] = t;
                    break;
                }
                stack.pop();
            }
        }
        stack.push(i);
    }
    return res;
};

