class Solution:
    def minimumDifference(self, nums: list[int]) -> int:
        from bisect import bisect_left
        n = len(nums) // 2
        total = sum(nums)
        left, right = nums[:n], nums[n:]
        def get_sums(arr):
            m = len(arr)
            sums = {}
            for mask in range(1 << m):
                s, cnt = 0, 0
                for i in range(m):
                    if mask & (1 << i):
                        s += arr[i]
                        cnt += 1
                sums.setdefault(cnt, []).append(s)
            return sums
        lsums = get_sums(left)
        rsums = get_sums(right)
        for k in rsums:
            rsums[k].sort()
        ans = float('inf')
        for k in range(n + 1):
            ls = lsums.get(k, [])
            rs = rsums.get(n - k, [])
            if not rs:
                continue
            for s in ls:
                target = total / 2 - s
                idx = bisect_left(rs, target)
                for j in [idx - 1, idx]:
                    if 0 <= j < len(rs):
                        part = s + rs[j]
                        ans = min(ans, abs(total - 2 * part))
        return ans

solution_js:
var minimumDifference = function(nums) {
    const n = nums.length / 2;
    const total = nums.reduce((a, b) => a + b, 0);
    const left = nums.slice(0, n), right = nums.slice(n);
    const getSums = (arr) => {
        const m = arr.length;
        const sums = new Map();
        for (let mask = 0; mask < (1 << m); mask++) {
            let s = 0, cnt = 0;
            for (let i = 0; i < m; i++) {
                if (mask & (1 << i)) { s += arr[i]; cnt++; }
            }
            if (!sums.has(cnt)) sums.set(cnt, []);
            sums.get(cnt).push(s);
        }
        return sums;
    };
    const lsums = getSums(left);
    const rsums = getSums(right);
    for (const [k, v] of rsums) v.sort((a, b) => a - b);
    let ans = Infinity;
    const bisect = (arr, t) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const mid = (lo + hi) >> 1; arr[mid] < t ? lo = mid + 1 : hi = mid; }
        return lo;
    };
    for (let k = 0; k <= n; k++) {
        const ls = lsums.get(k) || [];
        const rs = rsums.get(n - k) || [];
        if (!rs.length) continue;
        for (const s of ls) {
            const target = total / 2 - s;
            const idx = bisect(rs, target);
            for (const j of [idx - 1, idx]) {
                if (j >= 0 && j < rs.length) {
                    ans = Math.min(ans, Math.abs(total - 2 * (s + rs[j])));
                }
            }
        }
    }
    return ans;
};

