class Solution:
    def repairCars(self, ranks: list[int], cars: int) -> int:
        import math
        lo, hi = 1, min(ranks) * cars * cars
        while lo < hi:
            mid = (lo + hi) // 2
            total = sum(int(math.isqrt(mid // r)) for r in ranks)
            if total >= cars:
                hi = mid
            else:
                lo = mid + 1
        return lo

