        const mid = (lo + hi) / 2n;
        let total = 0n;
        for (const r of ranks) {
            const br = BigInt(r);
            const sq = BigInt(Math.floor(Math.sqrt(Number(mid / br))));
            total += sq;
        }
        if (total >= BigInt(cars)) {
            hi = mid;
        } else {
            lo = mid + 1n;
        }
    }
    return Number(lo);
};

