    def wiggleSort(self, nums: list[int]) -> None:
        sorted_nums = sorted(nums)
        n = len(nums)
        mid = (n - 1) // 2
        small = sorted_nums[:mid + 1][::-1]
        large = sorted_nums[mid + 1:][::-1]
