var wiggleSort = function(nums) {
    const sorted = [...nums].sort((a, b) => a - b);
    const n = nums.length;
    const mid = Math.floor((n - 1) / 2);
    const small = sorted.slice(0, mid + 1).reverse();
    const large = sorted.slice(mid + 1).reverse();
    for (let i = 0; i < small.length; i++) {
        nums[2 * i] = small[i];
    }
