class Solution:
    def splitArraySameAverage(self, nums: list[int]) -> bool:
        n = len(nums)
        total = sum(nums)
        if n == 1:
            return False
        nums = [x * n - total for x in nums]
        left = nums[:n // 2]
        right = nums[n // 2:]
        def get_sums(arr):
            res = {}
            for i in range(1, len(arr) + 1):
                for combo in __import__('itertools').combinations(arr, i):
                    s = sum(combo)
                    if i not in res:
                        res[i] = set()
                    res[i].add(s)
            return res
        left_sums = get_sums(left)
        right_sums = get_sums(right)
        for size in left_sums:
            if 0 in left_sums[size]:
                return True
        for size in right_sums:
            if 0 in right_sums[size]:
                return True
        for ls in left_sums:
            for rs in right_sums:
                if ls + rs < n:
                    for s in left_sums[ls]:
                        if -s in right_sums[rs]:
                            return True
        return False

solution_js:
var splitArraySameAverage = function(nums) {
    const n = nums.length;
    if (n === 1) return false;
    const total = nums.reduce((a, b) => a + b, 0);
    const arr = nums.map(x => x * n - total);
    const left = arr.slice(0, Math.floor(n / 2));
    const right = arr.slice(Math.floor(n / 2));
    function getSums(a) {
        const res = new Map();
        for (let i = 1; i <= a.length; i++) {
            const combos = combinations(a, i);
            for (const c of combos) {
                const s = c.reduce((x, y) => x + y, 0);
                if (!res.has(i)) res.set(i, new Set());
                res.get(i).add(s);
            }
        }
        return res;
    }
    function combinations(arr, k) {
        const result = [];
        function bt(start, combo) {
            if (combo.length === k) { result.push([...combo]); return; }
            for (let i = start; i < arr.length; i++) {
                combo.push(arr[i]);
                bt(i + 1, combo);
                combo.pop();
            }
        }
        bt(0, []);
        return result;
    }
    const leftSums = getSums(left);
    const rightSums = getSums(right);
    for (const [size, sums] of leftSums) {
        if (sums.has(0)) return true;
    }
    for (const [size, sums] of rightSums) {
        if (sums.has(0)) return true;
    }
    for (const [ls, lSet] of leftSums) {
        for (const [rs, rSet] of rightSums) {
            if (ls + rs < n) {
                for (const s of lSet) {
                    if (rSet.has(-s)) return true;
                }
            }
        }
    }
    return false;
};

