class Solution:
    def maxScore(self, nums1: list[int], nums2: list[int]) -> int:
        MOD = 10**9 + 7
        i, j = 0, 0
        sum1, sum2 = 0, 0
        while i < len(nums1) and j < len(nums2):
            if nums1[i] < nums2[j]:
                sum1 += nums1[i]
                i += 1
            elif nums1[i] > nums2[j]:
                sum2 += nums2[j]
                j += 1
            else:
                sum1 = sum2 = max(sum1, sum2) + nums1[i]
                i += 1
                j += 1
        while i < len(nums1):
            sum1 += nums1[i]
            i += 1
        while j < len(nums2):
            sum2 += nums2[j]
            j += 1
        return max(sum1, sum2) % MOD

solution_js:
var maxScore = function(nums1, nums2) {
    const MOD = 1e9 + 7;
    let i = 0, j = 0;
    let sum1 = 0, sum2 = 0;
    while (i < nums1.length && j < nums2.length) {
        if (nums1[i] < nums2[j]) {
            sum1 += nums1[i++];
        } else if (nums1[i] > nums2[j]) {
            sum2 += nums2[j++];
        } else {
            sum1 = sum2 = Math.max(sum1, sum2) + nums1[i];
            i++;
            j++;
        }
    }
    while (i < nums1.length) sum1 += nums1[i++];
    while (j < nums2.length) sum2 += nums2[j++];
    return Math.max(sum1, sum2) % MOD;
};

