class Solution:
    def majorityElement(self, nums: list[int]) -> list[int]:
        c1 = c2 = 0
        n1 = n2 = None
        for num in nums:
            if num == n1:
                c1 += 1
            elif num == n2:
                c2 += 1
            elif c1 == 0:
                n1, c1 = num, 1
            elif c2 == 0:
                n2, c2 = num, 1
            else:
                c1 -= 1
                c2 -= 1
        result = []
        for n in [n1, n2]:
            if n is not None and nums.count(n) > len(nums) // 3:
                result.append(n)
        return result

solution_js:
var majorityElement = function(nums) {
    let c1 = 0, c2 = 0, n1 = null, n2 = null;
    for (const num of nums) {
        if (num === n1) c1++;
        else if (num === n2) c2++;
        else if (c1 === 0) { n1 = num; c1 = 1; }
        else if (c2 === 0) { n2 = num; c2 = 1; }
        else { c1--; c2--; }
    }
    const result = [];
    for (const n of [n1, n2]) {
        if (n !== null && nums.filter(x => x === n).length > Math.floor(nums.length / 3)) {
            result.push(n);
        }
    }
    return result;
};

