class Solution:
    def longestBalancedSubstring(self, s: str) -> int:
        max_len = 0
        zeros = ones = 0
        for c in s:
            if c == '0':
                zeros += 1
            else:
                ones += 1
            if zeros == ones:
                max_len = max(max_len, zeros + ones)
            elif ones > zeros:
                zeros = ones = 0
        zeros = ones = 0
        for c in reversed(s):
            if c == '0':
                zeros += 1
            else:
                ones += 1
            if zeros == ones:
                max_len = max(max_len, zeros + ones)
            elif zeros > ones:
                zeros = ones = 0
        return max_len

solution_js:
var longestBalancedSubstring = function(s) {
    let maxLen = 0;
    let zeros = 0, ones = 0;
    for (const c of s) {
        if (c === '0') zeros++;
        else ones++;
        if (zeros === ones) maxLen = Math.max(maxLen, zeros + ones);
        else if (ones > zeros) zeros = ones = 0;
    }
    zeros = ones = 0;
    for (let i = s.length - 1; i >= 0; i--) {
        if (s[i] === '0') zeros++;
        else ones++;
        if (zeros === ones) maxLen = Math.max(maxLen, zeros + ones);
        else if (zeros > ones) zeros = ones = 0;
    }
    return maxLen;
};

