    const lps = new Array(n).fill(0);
    let len = 0, i = 1;
    while (i < n) {
        if (s[i] === s[len]) {
            len++;
            lps[i] = len;
            i++;
        } else {
            if (len !== 0) {
                len = lps[len - 1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
    }
    return s.substring(0, lps[n - 1]);
};

