class FirstUnique:
    def __init__(self, nums: list[int]):
        from collections import OrderedDict
        self.od = OrderedDict()
        self.duplicates = set()
        for num in nums:
            self.add(num)

    def showFirstUnique(self) -> int:
        if self.od:
            return next(iter(self.od))
        return -1

    def add(self, value: int) -> None:
        if value in self.duplicates:
            return
        if value in self.od:
            del self.od[value]
            self.duplicates.add(value)
        else:
            self.od[value] = True

