class Solution:
    def minDays(self, bloomDay: list[int], m: int, k: int) -> int:
        if m * k > len(bloomDay):
            return -1
        def canMake(days):
            bouquets = flowers = 0
            for b in bloomDay:
                if b <= days:
                    flowers += 1
                    if flowers == k:
                        bouquets += 1
                        flowers = 0
                else:
                    flowers = 0
            return bouquets >= m
        lo, hi = min(bloomDay), max(bloomDay)
        while lo < hi:
            mid = (lo + hi) // 2
            if canMake(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

solution_js:
var minDays = function(bloomDay, m, k) {
    if (m * k > bloomDay.length) return -1;
    function canMake(days) {
        let bouquets = 0, flowers = 0;
        for (const b of bloomDay) {
            if (b <= days) {
                flowers++;
                if (flowers === k) {
                    bouquets++;
                    flowers = 0;
                }
            } else {
                flowers = 0;
            }
        }
        return bouquets >= m;
    }
    let lo = Math.min(...bloomDay), hi = Math.max(...bloomDay);
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (canMake(mid)) hi = mid;
        else lo = mid + 1;
    }
    return lo;
};
